  // Hash an art-number to an int for deterministic pool indexing.
  const hash = (s) => {
    let h = 0; for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) | 0;
    return Math.abs(h);
  };

  // Standalone-bundle support: when window.__resources is populated by the
  // inliner, swap local packshot paths for blob URLs.
  const resolve = (path) => {
    if (!path) return path;
    if (window.__resources && window.__resources[path]) return window.__resources[path];
    return path;
  };

  window.packshotFor = function packshotFor(product) {
    // Case-insensitive lookup (DB uses both "1960520-SET" and "1960520-set" style)
    const local = BY_ART[product.art] || BY_ART[product.art.toLowerCase()];
    if (local) return resolve(local);
    const key = `${product.cat}/${product.sub || ""}`;
    const pool = POOLS[key] || POOLS[`${product.cat}/`];
    if (!pool || pool.length === 0) return null;
    const idx = hash(product.art) % pool.length;
    return u(pool[idx]);
  };
